import"./modulepreload-polyfill-3cfb730f.js";//! Код виконаного завдання
function e(o,n){return new Promise(s=>{setTimeout(()=>{s(o)},n)})}const t=[e("Проміс 1",1e3),e("Проміс 2",2e3),e("Проміс 3",1500),e("Проміс 4",3e3),e("Проміс 5",2500)];Promise.all(t).then(o=>{console.log("Результати всіх промісів:"),console.log(o)}).catch(o=>{console.log("Помилка:",o)}).finally(()=>{console.log("Всі проміси завершили роботу")});//! Код виконаного завдання
function l(o){const n=Math.floor(Math.random()*4e3)+1e3;return new Promise(s=>{setTimeout(()=>{s(o)},n)})}const c=[l("Проміс A"),l("Проміс B"),l("Проміс C"),l("Проміс D"),l("Проміс E")];Promise.race(c).then(o=>{console.log("Найшвидший проміс:",o)}).catch(o=>{console.log("Помилка:",o)}).finally(()=>{console.log("Змагання завершено")});
